"""Tests for the `architect report` command.

Covers Rich table rendering, JSON output, SUMMARY.md parsing,
project path resolution, and edge cases (missing, empty, corrupted files).
"""

from __future__ import annotations

import json
from pathlib import Path

from click.testing import CliRunner

from the_architect.cli import (
    _format_report_json,
    _parse_summary_md,
    main,
)

