# ---------------------------------------------------------------------------
# Test _parse_summary_md — parsing logic
# ---------------------------------------------------------------------------


class TestParseSummaryMd:
    """Tests for the _parse_summary_md helper function."""

    def test_parses_minimal_summary(self, tmp_path: Path) -> None:
        """Minimal SUMMARY.md is parsed correctly."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(MINIMAL_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["date"] == "2026-05-18 14:30"
        assert data["duration"] == "12:34"
        assert data["result"] == "success"
        assert data["goal"] == "Add a new feature to the application"
        assert len(data["tasks"]) == 1
        assert data["tasks"][0]["task"] == "T01"
        assert data["tasks"][0]["title"] == "setup_project"
        assert data["tasks"][0]["status"] == "✓ Done"

    def test_parses_multi_task_summary(self, tmp_path: Path) -> None:
        """Multi-task SUMMARY.md parses all task rows."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(MULTI_TASK_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert len(data["tasks"]) == 3
        assert data["tasks"][0]["task"] == "T01"
        assert data["tasks"][1]["task"] == "T02"
        assert data["tasks"][2]["task"] == "T03"
        assert data["tasks"][1]["attempts"] == "2"

    def test_parses_failed_result(self, tmp_path: Path) -> None:
        """SUMMARY.md with failed tasks produces result='failed'."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(FAILED_TASK_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["result"] == "failed"
        assert len(data["tasks"]) == 2
        assert data["tasks"][0]["status"] == "✓ Done"
        assert data["tasks"][1]["status"] == "✗ Failed"

    def test_parses_totals_section(self, tmp_path: Path) -> None:
        """Totals section is parsed into key-value pairs."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(MINIMAL_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert "Tasks" in data["totals"]
        assert data["totals"]["Tasks"] == "1/1 done"
        assert "Duration" in data["totals"]
        assert "Total tokens" in data["totals"]

    def test_parses_insights_section(self, tmp_path: Path) -> None:
        """Insights section is parsed into key-value pairs."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(MINIMAL_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert "Avg duration per task" in data["insights"]
        assert "Slowest task" in data["insights"]

    def test_parses_retrospective_summary(self, tmp_path: Path) -> None:
        """SUMMARY.md with retrospective rounds still parses tasks."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(RETROSPECTIVE_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["result"] == "success"
        assert len(data["tasks"]) == 1
        assert data["tasks"][0]["task"] == "T01"

    def test_skips_task_header_row(self, tmp_path: Path) -> None:
        """The header row of the tasks table is not included in output."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(MINIMAL_SUMMARY, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        # Header row has cells[0] == "Task" and must be skipped
        assert all(t["task"] != "Task" for t in data["tasks"])

    def test_empty_summary_returns_empty_fields(self, tmp_path: Path) -> None:
        """An empty SUMMARY.md returns a dict with empty/zeroed fields."""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text("", encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["date"] == ""
        assert data["duration"] == ""
        assert data["result"] == "unknown"
        assert data["goal"] == ""
        assert data["tasks"] == []
        assert data["totals"] == {}
        assert data["insights"] == {}

    def test_summary_with_no_goal_section(self, tmp_path: Path) -> None:
        """SUMMARY.md without a Goal section still parses."""
        content = """\
# The Architect — Run Summary

**Date:** 2026-05-18 14:30
**Duration:** 5:00
**Result:** ✓ All tasks completed

## Tasks

| Task | Title | Status | Attempts | Model | Duration | Tokens |
|------|-------|--------|----------|-------|----------|--------|
| T01 | test_task | ✓ Done | 1 | gpt-4o | 3:00 | 5K |

## Totals

- **Tasks:** 1/1 done
- **Duration:** 5:00
- **Total tokens:** 5K
"""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(content, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["goal"] == ""
        assert len(data["tasks"]) == 1

    def test_summary_with_no_insights_section(self, tmp_path: Path) -> None:
        """SUMMARY.md without Insights section still parses."""
        content = """\
# The Architect — Run Summary

**Date:** 2026-05-18 14:30
**Duration:** 5:00
**Result:** ✓ All tasks completed

## Tasks

| Task | Title | Status | Attempts | Model | Duration | Tokens |
|------|-------|--------|----------|-------|----------|--------|
| T01 | test_task | ✓ Done | 1 | gpt-4o | 3:00 | 5K |

## Totals

- **Tasks:** 1/1 done
- **Duration:** 5:00
- **Total tokens:** 5K
"""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(content, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        assert data is not None
        assert data["insights"] == {}

    def test_corrupted_summary_still_parses_partial(self, tmp_path: Path) -> None:
        """Corrupted SUMMARY.md still returns partial data."""
        content = """\
# The Architect — Run Summary

**Date:** 2026-05-18 14:30
**Duration:** 5:00
**Result:** ✓ All tasks completed

## Tasks

| Task | Title | Status
|------|-------|--------|
THIS IS CORRUPTED GARBAGE
"""
        tasks_dir = tmp_path / "tasks"
        tasks_dir.mkdir()
        summary_path = tasks_dir / "SUMMARY.md"
        summary_path.write_text(content, encoding="utf-8")

        data = _parse_summary_md(summary_path)

        # Should still parse what it can
        assert data is not None
        assert data["date"] == "2026-05-18 14:30"
